+
+        NOW.store(0, Ordering::SeqCst);
+        let first = Pin::new(&mut timed).poll_next(&mut context);
+        crate::assert_with_log!(
+            matches!(first, Poll::Ready(Some(Ok(_)))),
+            "item received",
+            true,
+            matches!(first, Poll::Ready(Some(Ok(_))))
+        );
+
+        NOW.store(5, Ordering::SeqCst);
